        }
        char first = Character.toUpperCase(postcode.charAt(0));
        if (first == 'W' || first == 'E' || first == 'N' || first == 'S') {
            return 0;
        }
        if (first >= 'A' && first <= 'M') {
            return 200;
        }
        return 400;
    }
}
